//go:build vectors

package search

import (
	"context"
	"path/filepath"
	"testing"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
	"github.com/a<HOME>/agentic-rag-mcp/internal/domain"
	"github.com/a<HOME>/agentic-rag-mcp/internal/embedder"
	"github.com/a<HOME>/agentic-rag-mcp/internal/ingest"
)

func setupTestSearcher(t *testing.T) (*Searcher, *ingest.Indexer) {
	t.Helper()
	dir := t.TempDir()
	indexPath := filepath.Join(dir, "test.bleve")

	ix, err := ingest.NewIndexer(indexPath, 768)
	if err != nil {
		t.Fatalf("NewIndexer: %v", err)
	}
	t.Cleanup(func() { ix.Close() })

	emb := embedder.NewMockEmbedder(768)
	cfg := config.SearchConfig{
		BM25Weight:   0.4,
		KNNWeight:    0.6,
		RRFK:         60,
		DefaultLimit: 5,
		MaxLimit:     20,
	}

	s := NewSearcher(ix.BleveIndex(), emb, cfg)
	return s, ix
}

func indexTestChunks(t *testing.T, ix *ingest.Indexer, emb *embedder.MockEmbedder) {
	t.Helper()
	ctx := context.Background()

	chunks := []domain.Chunk{
		{
			QualifiedID:  "fpf-spec:A.1",
			SectionID:    "A.1",
			DocumentSlug: "fpf-spec",
			Title:        "Trust in Claims",
			Content:      "Every claim from an external system must be verified at the trust boundary. Trust is not transitive.",
			Scope:        "global",
			Kind:         "reference",
			Tags:         []string{"trust", "security"},
			Position:     0,
		},
		{
			QualifiedID:  "fpf-spec:A.2",
			SectionID:    "A.2",
			DocumentSlug: "fpf-spec",
			Title:        "Fail-Safe Defaults",
			Content:      "When a system cannot determine the correct action, it must fail to the safer default.",
			Scope:        "global",
			Kind:         "reference",
			Tags:         []string{"security", "defaults"},
			Position:     1,
		},
		{
			QualifiedID:  "decision-009:decision",
			SectionID:    "decision",
			DocumentSlug: "decision-009",
			Title:        "Use nomic-embed-text for embeddings",
			Content:      "After evaluating MiniLM and other models, we chose nomic-embed-text for its 8192-token context window.",
			Scope:        "project",
			Kind:         "decision",
			Tags:         []string{"embedding", "model"},
			Position:     0,
		},
	}

	// Embed chunks
	for i := range chunks {
		text := chunks[i].Title + "\n\n" + chunks[i].Content
		vec, err := emb.Embed(ctx, text, embedder.PurposeIndex)
		if err != nil {
			t.Fatal(err)
		}
		chunks[i].Vector = vec
	}

	if err := ix.StoreChunks(chunks); err != nil {
		t.Fatal(err)
	}
}

func TestSearchEmptyIndex(t *testing.T) {
	s, _ := setupTestSearcher(t)

	resp, err := s.Search(context.Background(), "test query", "", "", nil, 5)
	if err != nil {
		t.Fatal(err)
	}
	if resp.IndexState != "empty" {
		t.Errorf("IndexState = %q, want %q", resp.IndexState, "empty")
	}
	if len(resp.Results) != 0 {
		t.Errorf("expected 0 results, got %d", len(resp.Results))
	}
}

func TestSearchBM25(t *testing.T) {
	s, ix := setupTestSearcher(t)
	emb := embedder.NewMockEmbedder(768)
	indexTestChunks(t, ix, emb)

	resp, err := s.Search(context.Background(), "trust claims verification", "", "", nil, 5)
	if err != nil {
		t.Fatal(err)
	}

	if resp.IndexState != "ready" {
		t.Errorf("IndexState = %q, want %q", resp.IndexState, "ready")
	}
	if len(resp.Results) == 0 {
		t.Fatal("expected at least 1 result")
	}
}

func TestSearchScopeFilter(t *testing.T) {
	s, ix := setupTestSearcher(t)
	emb := embedder.NewMockEmbedder(768)
	indexTestChunks(t, ix, emb)

	// Search global only
	resp, err := s.Search(context.Background(), "trust claims", "global", "", nil, 5)
	if err != nil {
		t.Fatal(err)
	}

	for _, r := range resp.Results {
		if r.Scope != "global" {
			t.Errorf("expected global scope, got %q for %s", r.Scope, r.QualifiedID)
		}
	}
}

func TestSearchKindFilter(t *testing.T) {
	s, ix := setupTestSearcher(t)
	emb := embedder.NewMockEmbedder(768)
	indexTestChunks(t, ix, emb)

	resp, err := s.Search(context.Background(), "embedding model", "", "decision", nil, 5)
	if err != nil {
		t.Fatal(err)
	}

	for _, r := range resp.Results {
		if r.Kind != "decision" {
			t.Errorf("expected kind=decision, got %q for %s", r.Kind, r.QualifiedID)
		}
	}
}

func TestSearchLimitCapping(t *testing.T) {
	s, ix := setupTestSearcher(t)
	emb := embedder.NewMockEmbedder(768)
	indexTestChunks(t, ix, emb)

	resp, err := s.Search(context.Background(), "system", "", "", nil, 1)
	if err != nil {
		t.Fatal(err)
	}
	if len(resp.Results) > 1 {
		t.Errorf("expected at most 1 result, got %d", len(resp.Results))
	}
}

func TestReadSection(t *testing.T) {
	s, ix := setupTestSearcher(t)
	emb := embedder.NewMockEmbedder(768)
	indexTestChunks(t, ix, emb)

	resp, err := s.Read("fpf-spec:A.1", 0)
	if err != nil {
		t.Fatal(err)
	}

	if !resp.Found {
		t.Fatal("expected Found=true")
	}
	if resp.Mode != "section" {
		t.Errorf("mode = %q, want %q", resp.Mode, "section")
	}
	if resp.Section == nil {
		t.Fatal("section should not be nil")
	}
	if resp.Section.Title != "Trust in Claims" {
		t.Errorf("title = %q, want %q", resp.Section.Title, "Trust in Claims")
	}
	if resp.Section.Content == "" {
		t.Error("content should not be empty")
	}
}

func TestReadDocumentTOC(t *testing.T) {
	s, ix := setupTestSearcher(t)
	emb := embedder.NewMockEmbedder(768)
	indexTestChunks(t, ix, emb)

	resp, err := s.Read("fpf-spec", 0)
	if err != nil {
		t.Fatal(err)
	}

	if !resp.Found {
		t.Fatal("expected Found=true")
	}
	if resp.Mode != "toc" {
		t.Errorf("mode = %q, want %q", resp.Mode, "toc")
	}
	if resp.Document == nil {
		t.Fatal("document should not be nil")
	}
	if len(resp.Sections) != 2 {
		t.Errorf("expected 2 sections, got %d", len(resp.Sections))
	}
}

func TestReadNotFound(t *testing.T) {
	s, _ := setupTestSearcher(t)

	resp, err := s.Read("nonexistent:section", 0)
	if err != nil {
		t.Fatal(err)
	}

	if resp.Found {
		t.Error("expected Found=false for nonexistent section")
	}
}

func TestReadContextExpansion(t *testing.T) {
	s, ix := setupTestSearcher(t)
	emb := embedder.NewMockEmbedder(768)
	indexTestChunks(t, ix, emb)

	resp, err := s.Read("fpf-spec:A.1", 1)
	if err != nil {
		t.Fatal(err)
	}

	if !resp.Found {
		t.Fatal("expected Found=true")
	}
	if resp.Section.SectionID != "A.1" {
		t.Errorf("section = %q, want A.1", resp.Section.SectionID)
	}
	// A.1 is position 0, context=1 should get A.2 (position 1)
	if len(resp.Context) == 0 {
		t.Error("expected context sections")
	}
}
